+import java.lang.invoke.MethodHandle;
+import java.lang.invoke.MethodHandles;
+import java.lang.invoke.MethodType;
@@ -53,0 +57,1 @@
+    private long beforeGcCpuTime;
@@ -58,0 +63,3 @@
+    private boolean gcCpuTimeSupported;
+
+    static final MemoryMXBean memoryBean = ManagementFactory.getPlatformMXBean(MemoryMXBean.class);
@@ -98,0 +106,16 @@
+
+        gcCpuTimeSupported = getTotalGcCpuTime() > -1;
+    }
+
+    private MethodHandle getTotalGcCpuTimeHandle = null;
+    private long getTotalGcCpuTime() {
+        try {
+            if (getTotalGcCpuTimeHandle == null) {
+                getTotalGcCpuTimeHandle = MethodHandles.lookup()
+                    .findVirtual(MemoryMXBean.class, "getTotalGcCpuTime", MethodType.methodType(long.class));
+            }
+            return getTotalGcCpuTimeHandle != null ? (long) getTotalGcCpuTimeHandle.invokeExact(memoryBean) : -1;
+        }
+        catch (Throwable e) {
+            return -1;
+        }
@@ -119,0 +143,4 @@
+
+        if (gcCpuTimeSupported) {
+            this.beforeGcCpuTime = getTotalGcCpuTime();
+        }
@@ -152,0 +180,8 @@
+        if (gcCpuTimeSupported) {
+            results.add(new ScalarResult(
+                "gc.cpuTime",
+                (getTotalGcCpuTime() - beforeGcCpuTime) / 1_000_000,
+                "ms",
+                AggregationPolicy.SUM));
+        }
+
